20: def doValidation() {
21:   // Run all the tasks associated with `check` except for `test` - the latter is executed via `doTest`
22:   sh """
23:     ./retry_zinc ./gradlew -PscalaVersion=$SCALA_VERSION clean check -x test \
24:         --profile --continue -PxmlSpotBugsReport=true -PkeepAliveMode="session"
25:   """
26: }
