28: def isChangeRequest(env) {
29:   env.CHANGE_ID != null && !env.CHANGE_ID.isEmpty()
30: }
31: 
32: def doTest(env, target = "test") {
33:   sh """./gradlew -PscalaVersion=$SCALA_VERSION ${target} \
34:       --profile --continue -PkeepAliveMode="session" -PtestLoggingEvents=started,passed,skipped,failed \
35:       -PignoreFailures=true -PmaxParallelForks=2 -PmaxTestRetries=1 -PmaxTestRetryFailures=10"""
36:   junit '**/build/test-results/**/TEST-*.xml'
37: }
38: 
39: def runTestOnDevBranch(env) {
40:   if (!isChangeRequest(env)) {
41:     doTest(env)
42:   }
43: }
